Here's a C++ function that converts markdown to HTML, handling the most common markdown features:

```cpp
#include <string>
#include <sstream>
#include <vector>
#include <regex>
#include <cctype>

// Escape HTML special characters
static std::string escapeHtml(const std::string& text) {
    std::string out;
    out.reserve(text.size());
    for (char c : text) {
        switch (c) {
            case '&': out += "&amp;";  break;
            case '<': out += "&lt;";   break;
            case '>': out += "&gt;";   break;
            case '"': out += "&quot;"; break;
            default:  out += c;        break;
        }
    }
    return out;
}

// Apply inline-level formatting: code, bold, italic, links, images.
static std::string parseInline(const std::string& text) {
    std::string result = escapeHtml(text);

    // Inline code: `code`  (do this early so its contents are not re-formatted)
    result = std::regex_replace(result, std::regex(R"(`([^`]+)`)"),
                                "<code>$1</code>");

    // Images: ![alt](url)
    result = std::regex_replace(result, std::regex(R"(!\[([^\]]*)\]\(([^)]+)\))"),
                                R"(<img src="$2" alt="$1">)");

    // Links: [text](url)
    result = std::regex_replace(result, std::regex(R"(\[([^\]]+)\]\(([^)]+)\))"),
                                R"(<a href="$2">$1</a>)");

    // Bold: **text** or __text__
    result = std::regex_replace(result, std::regex(R"(\*\*([^*]+)\*\*)"),
                                "<strong>$1</strong>");
    result = std::regex_replace(result, std::regex(R"(__([^_]+)__)"),
                                "<strong>$1</strong>");

    // Italic: *text* or _text_
    result = std::regex_replace(result, std::regex(R"(\*([^*]+)\*)"),
                                "<em>$1</em>");
    result = std::regex_replace(result, std::regex(R"(_([^_]+)_)"),
                                "<em>$1</em>");

    return result;
}

std::string markdownToHtml(const std::string& markdown) {
    std::istringstream stream(markdown);
    std::string line;
    std::ostringstream html;

    bool inUnorderedList = false;
    bool inOrderedList   = false;
    bool inCodeBlock     = false;
    bool inParagraph     = false;

    auto closeParagraph = [&]() {
        if (inParagraph) { html << "</p>\n"; inParagraph = false; }
    };
    auto closeLists = [&]() {
        if (inUnorderedList) { html << "</ul>\n"; inUnorderedList = false; }
        if (inOrderedList)   { html << "</ol>\n"; inOrderedList   = false; }
    };

    while (std::getline(stream, line)) {
        // Strip a trailing carriage return (Windows line endings)
        if (!line.empty() && line.back() == '\r') line.pop_back();

        // Fenced code blocks: ```
        if (line.rfind("```", 0) == 0) {
            if (!inCodeBlock) {
                closeParagraph();
                closeLists();
                html << "<pre><code>";
                inCodeBlock = true;
            } else {
                html << "</code></pre>\n";
                inCodeBlock = false;
            }
            continue;
        }
        if (inCodeBlock) {
            html << escapeHtml(line) << "\n";
            continue;
        }

        // Blank line: ends paragraphs and lists
        if (line.find_first_not_of(" \t") == std::string::npos) {
            closeParagraph();
            closeLists();
            continue;
        }

        std::smatch match;

        // Horizontal rule: ---, ***, ___
        if (std::regex_match(line, std::regex(R"(^\s*([-*_])\s*\1\s*\1[\s\1]*$)"))) {
            closeParagraph();
            closeLists();
            html << "<hr>\n";
            continue;
        }

        // Headers: # to ######
        if (std::regex_match(line, match, std::regex(R"(^(#{1,6})\s+(.*)$)"))) {
            closeParagraph();
            closeLists();
            int level = static_cast<int>(match[1].length());
            html << "<h" << level << ">"
                 << parseInline(match[2].str())
                 << "</h" << level << ">\n";
            continue;
        }

        // Blockquote: > text
        if (std::regex_match(line, match, std::regex(R"(^>\s?(.*)$)"))) {
            closeParagraph();
            closeLists();
            html << "<blockquote>" << parseInline(match[1].str())
                 << "</blockquote>\n";
            continue;
        }

        // Unordered list: -, *, or + followed by space
        if (std::regex_match(line, match, std::regex(R"(^\s*[-*+]\s+(.*)$)"))) {
            closeParagraph();
            if (inOrderedList) { html << "</ol>\n"; inOrderedList = false; }
            if (!inUnorderedList) { html << "<ul>\n"; inUnorderedList = true; }
            html << "  <li>" << parseInline(match[1].str()) << "</li>\n";
            continue;
        }

        // Ordered list: 1. text
        if (std::regex_match(line, match, std::regex(R"(^\s*\d+\.\s+(.*)$)"))) {
            closeParagraph();
            if (inUnorderedList) { html << "</ul>\n"; inUnorderedList = false; }
            if (!inOrderedList) { html << "<ol>\n"; inOrderedList = true; }
            html << "  <li>" << parseInline(match[1].str()) << "</li>\n";
            continue;
        }

        // Default: paragraph text
        closeLists();
        if (!inParagraph) {
            html << "<p>";
            inParagraph = true;
        } else {
            html << " "; // join wrapped lines within the same paragraph
        }
        html << parseInline(line);
    }

    // Close any still-open blocks at end of input
    closeParagraph();
    closeLists();
    if (inCodeBlock) html << "</code></pre>\n";

    return html.str();
}
```

## Usage Example

```cpp
#include <iostream>

int main() {
    std::string md =
        "# Hello World\n"
        "\n"
        "This is **bold** and *italic* and `code`.\n"
        "\n"
        "## A List\n"
        "- First item\n"
        "- Second item with a [link](https://example.com)\n"
        "\n"
        "> A blockquote\n"
        "\n"
        "```\n"
        "int x = 42;\n"
        "```\n";

    std::cout << markdownToHtml(md);
    return 0;
}
```

## Notes & Limitations

- **Features supported:** headers, bold, italic, inline code, fenced code blocks, links, images, unordered/ordered lists, blockquotes, horizontal rules, and paragraphs.
- **HTML escaping** is applied to text content so that raw `<`, `>`, and `&` are rendered safely.
- The signature in your question mentions a *reference* — I used `const std::string&` since the input isn't modified. If you specifically need a non-const reference, change the parameter to `std::string&`.
- This is a **lightweight, line-based parser**. It does not handle every edge case of the full CommonMark spec (nested lists, setext headers, reference-style links, tables, HTML passthrough, escaped characters like `\*`, etc.). For production-grade, fully-compliant parsing, consider a dedicated library such as **md4c**, **cmark**, or **maddy**.

